using MortgageMarketAnalysisAgent.Models.Documents;
using MortgageMarketAnalysisAgent.Models.Documents.Components;
using MortgageMarketAnalysisAgent.Models.RentCast;
using MortgageMarketAnalysisAgent.Models.UsRealEstate;
using MortgageMarketAnalysisAgent.Services.Interfaces;
using Newtonsoft.Json;
using System;
using System.Collections.Generic;
using System.Text;

namespace MortgageMarketAnalysisAgent.Clients;

public class UsRealEstateClient : IMarketAnalyzer
{
    private readonly IReportBuildingService _reportBuildingService;

    const string TARGET_PROPERTY_TYPE = "SINGLE_FAMILY";
    const string SUBJECT_ROLE = "SubjectBedroomBucket";
    const string ADJACENT_ROLE = "AdjacentBedroomAnchor";
    const string ANCHOR_NEXT_HIGHER = "NextHigherBedroomBucket";

    public UsRealEstateClient(IReportBuildingService reportBuildingService)
    {
        _reportBuildingService = reportBuildingService;
    }
    public async Task<IMarketValue> AnalyzeMarket(string zipcode)
    {
        var houses = await _reportBuildingService.BuildMarketHouseReport();

        var trends = JsonConvert.DeserializeObject<UsRealEstate>(marketTrends)!;

        return await Task.FromResult(trends);
    }

    public static List<MarketTrend> BuildRentCastDataSource(HousingMarketModel house, UsRealEstate trends)
    {
        List<MarketTrend> marketTrends = new List<MarketTrend>();

        var matchData = trends.results
                                       .Where(p =>
                                              p.bedrooms.Equals(house.BedRooms) &&
                                              p.bathrooms >= ((int)house.BathRooms) &&
                                              p.bathrooms <= ((int)house.BathRooms) &&
                                              //p.lotAreaValue <= house.SquareFootage - 1000 &&
                                              //p.lotAreaValue >= house.SquareFootage + 1000 &&
                                              p.homeType.Equals(TARGET_PROPERTY_TYPE, StringComparison.OrdinalIgnoreCase))
                                       .ToList();

        var upgradeData = trends.results
                               .Where(p =>
                                        p.bathrooms >= ((int)house.BathRooms) &&
                                        p.bathrooms <= ((int)house.BathRooms) &&
                                      //p.lotAreaValue <= house.SquareFootage-1000 &&
                                      //p.lotAreaValue >= house.SquareFootage+1000 ||
                                      p.bedrooms.Equals(house.BedRooms + 1)
                                      && p.homeType.Equals(TARGET_PROPERTY_TYPE, StringComparison.OrdinalIgnoreCase))
                               .ToList();

        var homeMatch = new BedroomMarketData
        {
            BedRooms = house.BedRooms,
            BathRooms = house.BathRooms,
            MedianPrice = matchData.Average(p => p.price),
            MedianSquareFootage = (int)matchData.Average(p => p.lotAreaValue),
            MedianPricePerSquareFoot = matchData.Average(p => p.price / p.lotAreaValue),
            TotalListings = matchData.Count(),
            MedianDaysOnMarket = (int)matchData.Average(p => TimeSpan.FromMilliseconds(p.timeOnZillow).Days)
        };

        var nextUpgrade = new BedroomMarketData
        {
            BedRooms = house.BedRooms+1,
            BathRooms = house.BathRooms,
            MedianPrice = upgradeData.Average(p => p.price),
            MedianSquareFootage = (int)upgradeData.Average(p => p.lotAreaValue),
            MedianPricePerSquareFoot = upgradeData.Average(p => p.price / p.lotAreaValue),
            TotalListings = upgradeData.Count(),
            MedianDaysOnMarket = (int)upgradeData.Average(p => TimeSpan.FromMilliseconds(p.timeOnZillow).Days)
        };

        var allData = new List<BedroomMarketData>
        {
            homeMatch, nextUpgrade
        };


        marketTrends.Add(new MarketTrend
        {
            Source = nameof(UsRealEstate),
            ZipCode = house.PostalCode,
            LastUpdated = DateTime.Today,
            PropertyTypeMarketData = new List<PropertyTypeMarketData> {
                new PropertyTypeMarketData
                {
                    PropertyType = TARGET_PROPERTY_TYPE,
                    MedianPrice = homeMatch.MedianPrice,
                    MedianPricePerSquareFoot = homeMatch.MedianPricePerSquareFoot,
                    MedianSquareFootage = homeMatch.MedianSquareFootage,
                    TotalListings = homeMatch.TotalListings,
                    MedianDaysOnMarket = homeMatch.MedianDaysOnMarket
                } },
            BedroomMarketData = allData.Select(p =>
            {
                return new BedroomMarketData
                {
                    Role = p.BedRooms == house.BedRooms ? SUBJECT_ROLE : ADJACENT_ROLE,
                    AnchorDirection = p.BedRooms > house.BedRooms ? ANCHOR_NEXT_HIGHER : null,
                    BedRooms = p.BedRooms,
                    BathRooms = house.BathRooms,
                    MedianPrice = p.MedianPrice,
                    MedianPricePerSquareFoot = p.MedianPricePerSquareFoot,
                    MedianSquareFootage = (int)p.MedianSquareFootage,
                    TotalListings = p.TotalListings,
                    MedianDaysOnMarket = p.MedianDaysOnMarket,
                    PropertyType = TARGET_PROPERTY_TYPE,
                    PropertyTypeMedian = p.BedRooms == house.BedRooms ? (int)p.MedianPrice : 0,
                    propertyTypeMedianPricePerSquareFoot = p.BedRooms == house.BedRooms ? p.MedianPricePerSquareFoot : 0
                };               
            }).ToList()
        });

        return marketTrends;
    }

